package org.apache.commons.compress.archivers.zip;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.apache.commons.compress.archivers.zip.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
    // This is a JUnit runner class for Cucumber tests
}

package org.apache.commons.compress.archivers.zip.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.compress.archivers.zip.X5455_ExtendedTimestamp;
import static org.junit.Assert.*;

public class StepDefs {

    private X5455_ExtendedTimestamp x5455Instance;
    private Exception caughtException;

    @Given("I have a X5455_ExtendedTimestamp instance")
    public void i_have_a_x5455_extendedtimestamp_instance() {
        x5455Instance = new X5455_ExtendedTimestamp();
    }

    @When("I attempt to set the Modify Java Time to {long} seconds past epoch")
    public void i_attempt_to_set_the_modify_java_time_to_seconds_past_epoch(long seconds) {
        try {
            x5455Instance.setModifyJavaTimeUTC(seconds);
            caughtException = null;
        } catch (Exception e) {
            caughtException = e;
        }
    }

    @Then("the operation should fail with an IllegalArgumentException")
    public void the_operation_should_fail_with_an_illegalArgumentException() {
        assertNotNull("Expected an exception but none was thrown", caughtException);
        assertTrue("Expected IllegalArgumentException but got " + caughtException.getClass().getSimpleName(), 
                   caughtException instanceof IllegalArgumentException);
    }

    @Then("the exception message should contain {string}")
    public void the_exception_message_should_contain(String expectedMessage) {
        assertNotNull("No exception was caught", caughtException);
        assertTrue("Exception message does not contain expected text: " + expectedMessage, 
                   caughtException.getMessage().contains(expectedMessage));
    }
}

